parameters.jsCode:
// This function expects that the previous node output contains the shareable URL in a field, e.g. "imageUrl".
const shareableUrl = $input.first().json.webViewLink; // Adjust the field name if necessary

// Extract the file ID from the shareable URL.
let fileId = "";
const match = shareableUrl.match(/\/d\/([^\/]+)/);
if (match && match[1]) {
    fileId = match[1];
}

// Build the direct URL if a file ID is found.
if (fileId) {
    items[0].json.directImageUrl = `https://drive.google.com/uc?export=view&id=${fileId}`;
} else {
    // Fallback: use the original URL if no file ID was extracted.
    items[0].json.directImageUrl = shareableUrl;
}

return items;

const input = $json["text"] || $json["text"] || "";  // Match your actual field name
const finalLine = "To infuse your days with even more positivity and high energy, visit http://TheDailyEnergizer.com for a special dose of upliftment and motivation to jumpstart your day!";
const maxLength = 3000;

let cleaned = input.trim();

// If it's already there, just trim to max
if (cleaned.includes("https://WCN.One")) {
  return {
    json: {
      content: cleaned.length > maxLength ? cleaned.slice(0, maxLength).trim() : cleaned
    }
  };
}

// Reserve space for final line + line breaks
const reservedSpace = finalLine.length + 2; // +2 for line breaks
const allowedLength = maxLength - reservedSpace;

// Trim the main content
let trimmed = cleaned.slice(0, allowedLength).trim();

// Add final line
const full = trimmed + "\n\n" + finalLine;

return {
  json: {
    content: full
  }
};

// Get all input items
const items = $input.all();

// Find the maximum row number
let maxRowNumber = -Infinity;
let maxItem = null;

for (const item of items) {
  const rowNumber = item.json.row_number;
  if (rowNumber > maxRowNumber) {
    maxRowNumber = rowNumber;
    maxItem = item;
  }
}

// Return the item with the maximum row number
return maxItem ? [maxItem] : [];

parameters.text:
={{ $json.Article }}

Now, using the above story, write a summary of the the full Daily Energizer article WITHOUT the references to the infinite universe, daily practices, or microorganisms that live inside us. The story should be 200-300 words max. Create one of the most uplifting, super-charged, inspiring and energizing summaries ever!

Don't ever use emojis!

parameters.jsCode:
const stories = items[0].json.stories;

const formatted = stories.map((story, index) => {
  return `Story ${index + 1}:\nTitle: ${story.title}\nSummary: ${story.summary}\n`;
}).join('\n');

return [{
  json: {
    promptText: formatted
  }
}];
